const items = $input.all();

const invoice = {
  invoice: {
    number: items[0].json.PINO,
    currency: "EUR"
  },
  client: {
    code: (items[0].json.TIERS || "").trim()
  },
  lines: [],
  totals: {
    ht: 0,
    ttc: 0
  }
};

const COEF = 2.5;       // adjust if needed
const DISCOUNT = 0.02;  // 2% from PDF

for (const item of items) {
  const basePrice = Number(item.json.CR || 0);
  const quantity = Number(item.json.QTE || 0);

  // 🔥 apply discount
  const unit_price = basePrice * COEF;
  const discounted_price = unit_price * (1 - DISCOUNT);

  const total_ht = discounted_price * quantity;

  invoice.lines.push({
    reference: (item.json.REF || "").trim(),
    quantity,
    unit_price: discounted_price,
    total_ht
  });

  invoice.totals.ht += total_ht;
}

// TVA ~ 19.7% (based on your data)
invoice.totals.ttc = invoice.totals.ht * 1.197;

return [{ json: invoice }];
